<header><div><h1>Motoristas</h1><span>Gerenciamento de Motoristas</span></div></header>
<section class="cards"><div class="card"><small>Total</small><h2><?= count($motoristas) ?></h2></div><div class="card"><small>Disponíveis</small><h2><?= count(array_filter($motoristas, fn ($motorista) => $motorista->isDisponivel())) ?></h2></div></section>
<section class="table-card"><div class="title">Adicionar motorista</div><form method="post" class="inline-form"><input type="hidden" name="acao" value="criar_motorista"><input name="nome" placeholder="Nome" required><input name="cpf" placeholder="CPF" required><input name="cnh" placeholder="CNH" required><input name="categoria" placeholder="Categoria" required><button class="btn" type="submit">Adicionar</button></form></section>
<section class="table-card"><div class="title">Motoristas</div><table><thead><tr><th>Nome</th><th>CNH</th><th>Categoria</th><th>Status</th><th>Ações</th></tr></thead><tbody><?php foreach ($motoristas as $motorista): ?><tr><td><?= esc($motorista->getNome()) ?></td><td><?= esc($motorista->getCnh()) ?></td><td><?= esc($motorista->getCategoria()) ?></td><td><span class="<?= $motorista->isDisponivel() ? 'success' : 'warning' ?>"><?= $motorista->isDisponivel() ? 'Disponível' : 'Em rota' ?></span></td><td><div class="inline-action"><form method="post"><input type="hidden" name="acao" value="remover_motorista"><input type="hidden" name="id" value="<?= $motorista->getId() ?>"><button class="btn danger" type="submit">Remover</button></form></div></td></tr><?php endforeach; ?></tbody></table></section>
